diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..7ae2c1e733f0 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4630,6 +4630,37 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
       return ConstantInt::getFalse(Cond->getType());
   }

+  // select (select X, Y, false), true, Y --> Y
+  // select (select C, TV, false), all-ones, C --> C
+  if (auto *CondSI = dyn_cast<SelectInst>(Cond))
+    if (match(TrueVal, m_One()) &&
+        match(CondSI->getFalseValue(), m_ZeroInt())) {
+      // Don't fold if the inner select's false value contains poison.
+      if (auto *C = dyn_cast<Constant>(CondSI->getFalseValue()))
+        if (C->containsPoisonElement())
+          return nullptr;
+      if (CondSI->getTrueValue() == FalseVal)
+        return FalseVal;
+      // select (select C, TV, false), all-ones, C --> C
+      if (CondSI->getCondition() == FalseVal)
+        return FalseVal;
+    }
+
+  // select C, all-ones, (select X, C, 0) --> C
+  if (auto *FalseSI = dyn_cast<SelectInst>(FalseVal))
+    if (match(TrueVal, m_One()) &&
+        match(FalseSI->getFalseValue(), m_ZeroInt()) &&
+        FalseSI->getTrueValue() == Cond) {
+      // Don't fold if the inner select's false value contains poison.
+      if (auto *C = dyn_cast<Constant>(FalseSI->getFalseValue()))
+        if (C->containsPoisonElement())
+          return nullptr;
+      return Cond;
+    }
+
+
+
+
   // If the true or false value is poison, we can fold to the other value.
   // If the true or false value is undef, we can fold to the other value as
   // long as the other value isn't poison.

